## 2. Context & DataLoader Setup (N+1 Solution)
DataLoaders batch and cache requests per execution tick, eliminating N+1.

```typescript
import DataLoader from 'dataloader';
import { Redis } from 'ioredis';
import { PubSub } from 'graphql-subscriptions';

export interface Context {
  userId: string;
  loaders: Loaders;
  pubsub: PubSub;
  db: any; // Prisma/Knex/etc.
}

interface Loaders {
  userById: DataLoader<string, User>;
  postAuthor: DataLoader<string, User>;
  commentsByPost: DataLoader<string, Comment[]>;
  likesByTarget: DataLoader<string, number>; // targetId -> count
  viewerLikedTarget: DataLoader<string, boolean>; // "postId:userId" -> boolean
}

export function createLoaders(db: any): Loaders {
  return {
    userById: new DataLoader(async (ids) => {
      const users = await db.user.findMany({ where: { id: { in: ids } } });
      return ids.map(id => users.find(u => u.id === id));
    }),

    postAuthor: new DataLoader(async (postIds) => {
      const posts = await db.post.findMany({
        where: { id: { in: postIds } },
        select: { id: true, authorId: true }
      });
      const authorIds = posts.map(p => p.authorId);
      const authors = await db.user.findMany({ where: { id: { in: authorIds } } });
      return postIds.map(pid => {
        const post = posts.find(p => p.id === pid);
        return authors.find(u => u.id === post.authorId);
      });
    }),

    commentsByPost: new DataLoader(async (postIds) => {
      const comments = await db.comment.findMany({
        where: { postId: { in: postIds } },
        orderBy: { createdAt: 'desc' }
      });
      return postIds.map(pid => comments.filter(c => c.postId === pid));
    }),

    likesByTarget: new DataLoader(async (targetIds) => {
      const counts = await db.like.groupBy({
        by: ['targetId'],
        where: { targetId: { in: targetIds } },
        _count: { targetId: true }
      });
      return targetIds.map(tid => 
        counts.find(c => c.targetId === tid)?._count.targetId || 0
      );
    }),

    viewerLikedTarget: new DataLoader(async (keys) => {
      // keys format: "targetId:userId"
      const parsed = keys.map(k => {
        const [targetId, userId] = k.split(':');
        return { targetId, userId };
      });
      const likes = await db.like.findMany({
        where: { OR: parsed.map(p => ({ targetId: p.targetId, userId: p.userId })) }
      });
      return keys.map(k => {
        const [targetId, userId] = k.split(':');
        return likes.some(l => l.targetId === targetId && l.userId === userId);
      });
    })
