## 3. Cursor-Based Pagination Utility
Encodes `createdAt:id` to handle chronological sorting safely.

```typescript
export function encodeCursor(date: Date, id: string): string {
  return Buffer.from(`${date.getTime()}:${id}`).toString('base64');
}

export function decodeCursor(cursor: string): { time: number; id: string } {
  const [time, id] = Buffer.from(cursor, 'base64').toString().split(':');
  return { time: parseInt(time, 10), id };
}

export async function buildConnection<T>(
  items: T[],
  first: number,
  after?: string,
  totalCount: number = 0
) {
  const hasNextPage = items.length > first;
  const sliced = items.slice(0, first);

  const edges = sliced.map((item, i) => ({
    cursor: encodeCursor((item as any).createdAt, (item as any).id),
    node: item
  }));

  return {
    pageInfo: {
      hasNextPage,
      hasPreviousPage: !!after,
      startCursor: edges[0]?.cursor,
      endCursor: edges[edges.length - 1]?.cursor
    },
    edges,
    totalCount
  };
}
```

