// dataloaders.js
const DataLoader = require('dataloader');

class DataLoaders {
  constructor(db) {
    this.db = db;

    // User loaders
    this.userLoader = new DataLoader(async (ids) => {
      const users = await this.db.users.findMany({
        where: { id: { in: ids } }
      });
      const userMap = new Map(users.map(u => [u.id, u]));
      return ids.map(id => userMap.get(id) || null);
    });

    // Post loaders
    this.postLoader = new DataLoader(async (ids) => {
      const posts = await this.db.posts.findMany({
        where: { id: { in: ids } },
        include: { author: true }
      });
      const postMap = new Map(posts.map(p => [p.id, p]));
      return ids.map(id => postMap.get(id) || null);
    });

    // Batch loaders for relationships
    this.postsByUserLoader = new DataLoader(async (userIds) => {
      const posts = await this.db.posts.findMany({
        where: { authorId: { in: userIds } },
        orderBy: { createdAt: 'desc' }
      });
      return userIds.map(id => posts.filter(p => p.authorId === id));
    });

    this.likesByPostLoader = new DataLoader(async (postIds) => {
      const likes = await this.db.likes.findMany({
        where: { postId: { in: postIds } },
        include: { user: true }
      });
      return postIds.map(id => likes.filter(l => l.postId === id));
    });

    this.commentsByPostLoader = new DataLoader(async (postIds) => {
      const comments = await this.db.comments.findMany({
        where: { postId: { in: postIds }, parentCommentId: null },
        include: { author: true }
      });
      return postIds.map(id => comments.filter(c => c.postId === id));
    });

    this.followersByUserLoader = new DataLoader(async (userIds) => {
      const follows = await this.db.follows.findMany({
        where: { followingId: { in: userIds } },
        include: { follower: true }
      });
      return userIds.map(id => 
        follows.filter(f => f.followingId === id).map(f => f.follower)
      );
    });

    this.followingByUserLoader = new DataLoader(async (userIds) => {
      const follows = await this.db.follows.findMany({
        where: { followerId: { in: userIds } },
        include: { following: true }
      });
      return userIds.map(id => 
        follows.filter(f => f.followerId === id).map(f => f.following)
      );
    });
  }

  clearCache() {
    Object.values(this).forEach(loader => {
      if (loader.clearAll) loader.clearAll();
    });
  }
}

