    likes: async (parent, { first = 10, after }, { loaders }) => {
      const likes = await loaders.likesByPostLoader.load(parent.id);
      return cursorPaginate(likes, first, after);
    },

    comments: async (parent, { first = 10, after }, { loaders }) => {
      const comments = await loaders.commentsByPostLoader.load(parent.id);
      return cursorPaginate(comments, first, after);
    },

    likesCount: async (parent, _, { db }) => {
      return db.likes.count({ where: { postId: parent.id } });
    },

    commentsCount: async (parent, _, { db }) => {
      return db.comments.count({ where: { postId: parent.id } });
    },

    isLikedByMe: async (parent, _, { userId, db }) => {
      if (!userId) return false;
      const like = await db.likes.findFirst({
        where: { userId, postId: parent.id }
      });
      return !!like;
    }
  },

  Comment: {
    author: (parent, _, { loaders }) => {
      return loaders.userLoader.load(parent.authorId);
    },

    post: (parent, _, { loaders }) => {
      return loaders.postLoader.load(parent.postId);
    },

    parentComment: async (parent, _, { loaders }) => {
      if (!parent.parentCommentId) return null;
      return loaders.commentLoader.load(parent.parentCommentId);
    },

    replies: async (parent, { first = 10, after }, { db }) => {
      const replies = await db.comments.findMany({
        where: { parentCommentId: parent.id },
        orderBy: { createdAt: 'asc' }
      });
      return cursorPaginate(replies, first, after);
    },

    likesCount: async (parent, _, { db }) => {
      return db.likes.count({ where: { commentId: parent.id } });
    },

    repliesCount: async (parent, _, { db }) => {
      return db.comments.count({ where: { parentCommentId: parent.id } });
    }
  }
};

// Helper functions
function decodeCursor(cursor) {
  return Buffer.from(cursor, 'base64').toString('utf-8');
}

function encodeCursor(id) {
  return Buffer.from(id).toString('base64');
}

function createConnection(items, first, type) {
  const hasNextPage = items.length > first;
  const edges = items.slice(0, first).map(item => ({
    node: item,
    cursor: encodeCursor(item.id)
  }));

  return {
    edges,
    pageInfo: {
      hasNextPage,
      hasPreviousPage: false,
      startCursor: edges[0]?.cursor,
      endCursor: edges[edges.length - 1]?.cursor
    },
    totalCount: edges.length
  };
}

function cursorPaginate(items, first, after) {
  if (!items || items.length === 0) {
    return createConnection([], first, 'default');
  }

  let startIndex = 0;
  if (after) {
    const afterId = decodeCursor(after);
    startIndex = items.findIndex(item => item.id === afterId) + 1;
  }

  const paginatedItems = items.slice(startIndex, startIndex + first + 1);
  return createConnection(paginatedItems, first, 'paginated');
}

// Input validation functions
function validateSignUpInput(input) {
  const usernameRegex = /^[a-zA-Z0-9_]+$/;
  if (!usernameRegex.test(input.username)) {
    throw new GraphQLError('Username can only contain letters, numbers, and underscores');
  }

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailRegex.test(input.email)) {
    throw new GraphQLError('Invalid email format');
  }

  if (input.password.length < 8) {
    throw new GraphQLError('Password must be at least 8 characters');
  }
}

function validatePostInput(input) {
  if (input.content.length === 0 || input.content.length > 5000) {
    throw new GraphQLError('Post content must be between 1 and 5000 characters');
  }

  if (input.mediaUrls && input.mediaUrls.length > 10) {
    throw new GraphQLError('Maximum 10 media URLs allowed');
  }
}

function validateCommentInput(input) {
  if (input.content.length === 0 || input.content.length > 1000) {
    throw new GraphQLError('Comment must be between 1 and 1000 characters');
  }
}

module.exports = resolvers;
