## 4. Server Setup with Rate Limiting

```javascript
// server.js
const { ApolloServer } = require('apollo-server-express');
const { makeExecutableSchema } = require('@graphql-tools/schema');
const { applyMiddleware } = require('graphql-middleware');
const express = require('express');
const depthLimit = require('graphql-depth-limit');
const { createComplexityLimitRule } = require('graphql-validation-complexity');
const DataLoaders = require('./dataloaders');
const schema = require('./schema');
const resolvers = require('./resolvers');
const rateLimit = require('express-rate-limit');

// Create executable schema
const executableSchema = makeExecutableSchema({
  typeDefs: schema,
  resolvers
});

// Rate limiting middleware
const globalRateLimit = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100 // limit each IP to 100 requests per windowMs
});

// Field-level rate limiting middleware
const fieldRateLimiting = async (resolve, root, args, context, info) => {
  const fieldPath = `${info.parentType}.${info.fieldName}`;
  const limiter = fieldRateLimits[fieldPath];

  if (limiter) {
    const req = context.req;
    await new Promise((resolvePromise, reject) => {
      limiter(req, {}, (err) => {
        if (err) reject(new GraphQLError('Rate limit exceeded'));
        else resolvePromise();
      });
    });
  }

  return resolve(root, args, context, info);
};

const middleware = {
  Query: fieldRateLimiting,
  Mutation: fieldRateLimiting
};

const schemaWithMiddleware = applyMiddleware(executableSchema, middleware);

// Context creation
const context = async ({ req, connection }) => {
  if (connection) {
    // For subscriptions
    return connection.context;
  }

  // For queries/mutations
  const token = req.headers.authorization?.replace('Bearer ', '');
  let userId = null;

  if (token) {
    try {
      const decoded = verifyToken(token);
      userId = decoded.userId;
    } catch (error) {
      // Invalid token
    }
  }

  // Initialize DataLoaders per request
  const loaders = new DataLoaders(db);

  return {
    userId,
    loaders,
    db,
    req
  };
};

// Create Apollo Server
const server = new ApolloServer({
  schema: schemaWithMiddleware,
  context,
  validationRules: [
    depthLimit(10), // Limit query depth
    createComplexityLimitRule(1000, {
      onCost: (cost) => {
        console.log(`Query cost: ${cost}`);
      }
    })
  ],
  subscriptions: {
    onConnect: (connectionParams, webSocket) => {
      const token = connectionParams.authorization?.replace('Bearer ', '');
      if (token) {
        try {
          const decoded = verifyToken(token);
          return { userId: decoded.userId };
        } catch (error) {
          throw new Error('Invalid token');
        }
      }
      throw new Error('Missing authentication token');
    }
  },
  plugins: [
    {
      requestDidStart: async (requestContext) => {
        // Clear DataLoader cache on mutation
        if (requestContext.request.operationName === 'Mutation') {
          requestContext.context.loaders.clearCache();
        }

        return {
          willSendResponse: async (responseContext) => {
            // Add cache headers
            responseContext.response.http.headers.set(
              'Cache-Control',
              'no-cache, no-store, must-revalidate'
            );
          }
        };
      }
    }
  ]
});

// Start server
const app = express();
app.use(globalRateLimit);
server.applyMiddleware({ app });
server.installSubscriptionHandlers(app);

const PORT = process.env.PORT || 4000;
app.listen(PORT, () => {
  console.log(`Server ready at http://localhost:${PORT}${server.graphqlPath}`);
  console.log(`Subscriptions ready at ws://localhost:${PORT}${server.subscriptionsPath}`);
});
```

## Key Features Implemented:

1. **DataLoader Pattern**: Prevents N+1 queries by batching and caching database requests
2. **Cursor-based Pagination**: Efficient pagination with opaque cursors for all connection types
3. **Input Validation**: Comprehensive validation using custom directives and resolver validation
4. **Rate Limiting**: Both global and field-level rate limiting
5. **Real-time Subscriptions**: WebSocket-based subscriptions for live updates
6. **Complexity Limits**: Prevents overly complex queries
7. **Query Depth Limiting**: Protects against malicious deep queries
8. **Proper Error Handling**: GraphQL errors with appropriate codes and messages
9. **Authentication Context**: JWT-based auth for both HTTP and WebSocket connections
10. **Cache Control**: Proper HTTP cache headers

This schema handles the most complex social media interactions efficiently while maintaining performance and security.
